import type { BiquadCoeffs, BiquadState } from "../../Types/audio.js";
import type { AudioEffect } from "./BaseEffect.js";

export function calcLowShelfCoeffs(
  freq: number,
  sampleRate: number,
  gainDb: number,
  Q = 0.7,
): BiquadCoeffs {
  const A = Math.pow(10, gainDb / 40);
  const w0 = (2 * Math.PI * freq) / sampleRate;
  const cosW0 = Math.cos(w0);
  const sinW0 = Math.sin(w0);
  const alpha = (sinW0 / 2) * Math.sqrt((A + 1 / A) * (1 / Q - 1) + 2);
  const sqrtA2Alpha = 2 * Math.sqrt(A) * alpha;

  const b0 = A * (A + 1 - (A - 1) * cosW0 + sqrtA2Alpha);
  const b1 = 2 * A * (A - 1 - (A + 1) * cosW0);
  const b2 = A * (A + 1 - (A - 1) * cosW0 - sqrtA2Alpha);
  const a0 = A + 1 + (A - 1) * cosW0 + sqrtA2Alpha;
  const a1 = -2 * (A - 1 + (A + 1) * cosW0);
  const a2 = A + 1 + (A - 1) * cosW0 - sqrtA2Alpha;

  return { b0: b0 / a0, b1: b1 / a0, b2: b2 / a0, a1: a1 / a0, a2: a2 / a0 };
}

export function calcHighShelfCoeffs(
  freq: number,
  sampleRate: number,
  gainDb: number,
  Q = 0.7,
): BiquadCoeffs {
  const A = Math.pow(10, gainDb / 40);
  const w0 = (2 * Math.PI * freq) / sampleRate;
  const cosW0 = Math.cos(w0);
  const sinW0 = Math.sin(w0);
  const alpha = (sinW0 / 2) * Math.sqrt((A + 1 / A) * (1 / Q - 1) + 2);
  const sqrtA2Alpha = 2 * Math.sqrt(A) * alpha;

  const b0 = A * (A + 1 + (A - 1) * cosW0 + sqrtA2Alpha);
  const b1 = -2 * A * (A - 1 + (A + 1) * cosW0);
  const b2 = A * (A + 1 + (A - 1) * cosW0 - sqrtA2Alpha);
  const a0 = A + 1 - (A - 1) * cosW0 + sqrtA2Alpha;
  const a1 = 2 * (A - 1 - (A + 1) * cosW0);
  const a2 = A + 1 - (A - 1) * cosW0 - sqrtA2Alpha;

  return { b0: b0 / a0, b1: b1 / a0, b2: b2 / a0, a1: a1 / a0, a2: a2 / a0 };
}

export function calcPeakingCoeffs(freq: number, sampleRate: number, gainDb: number, Q: number): BiquadCoeffs {
  const A = Math.pow(10, gainDb / 40);
  const w0 = (2 * Math.PI * freq) / sampleRate;
  const cosW0 = Math.cos(w0);
  const sinW0 = Math.sin(w0);
  const alpha = sinW0 / (2 * Q);

  const b0 = 1 + alpha * A;
  const b1 = -2 * cosW0;
  const b2 = 1 - alpha * A;
  const a0 = 1 + alpha / A;
  const a1 = -2 * cosW0;
  const a2 = 1 - alpha / A;

  return { b0: b0 / a0, b1: b1 / a0, b2: b2 / a0, a1: a1 / a0, a2: a2 / a0 };
}

export function processBiquad(input: number, coeffs: BiquadCoeffs, state: BiquadState): number {
  const output =
    coeffs.b0 * input +
    coeffs.b1 * state.x1 +
    coeffs.b2 * state.x2 -
    coeffs.a1 * state.y1 -
    coeffs.a2 * state.y2;

  state.x2 = state.x1;
  state.x1 = input;
  state.y2 = state.y1;
  state.y1 = output;

  return output;
}

function processBiquadChannel(
  samples: Float64Array,
  offset: number,
  stride: number,
  count: number,
  shelfCoeffs: BiquadCoeffs | null,
  peakCoeffs: BiquadCoeffs | null,
  shelfState: BiquadState,
  peakState: BiquadState,
): void {
  if (!shelfCoeffs) return;

  let x1 = shelfState.x1, x2 = shelfState.x2, y1 = shelfState.y1, y2 = shelfState.y2;
  let px1 = peakState.x1, px2 = peakState.x2, py1 = peakState.y1, py2 = peakState.y2;
  const { b0, b1, b2, a1, a2 } = shelfCoeffs;
  const hasPeak = peakCoeffs !== null;
  const pb0 = hasPeak ? peakCoeffs!.b0 : 0;
  const pb1 = hasPeak ? peakCoeffs!.b1 : 0;
  const pb2 = hasPeak ? peakCoeffs!.b2 : 0;
  const pa1 = hasPeak ? peakCoeffs!.a1 : 0;
  const pa2 = hasPeak ? peakCoeffs!.a2 : 0;

  for (let f = 0; f < count; f++) {
    const idx = f * stride + offset;
    let v = samples[idx]!;
    let out = b0 * v + b1 * x1 + b2 * x2 - a1 * y1 - a2 * y2;

    x2 = x1;
    x1 = v;
    y2 = y1;
    y1 = out;

    if (hasPeak) {
      v = out;
      out = pb0 * v + pb1 * px1 + pb2 * px2 - pa1 * py1 - pa2 * py2;

      px2 = px1;
      px1 = v;
      py2 = py1;
      py1 = out;
    }

    samples[idx] = out;
  }

  shelfState.x1 = x1;
  shelfState.x2 = x2;
  shelfState.y1 = y1;
  shelfState.y2 = y2;
  peakState.x1 = px1;
  peakState.x2 = px2;
  peakState.y1 = py1;
  peakState.y2 = py2;
}

export type BiquadCoeffsFn = () => { shelf: BiquadCoeffs; peak: BiquadCoeffs | null };

export class BiquadEffect implements AudioEffect {
  private coeffs: { shelf: BiquadCoeffs; peak: BiquadCoeffs | null } | null = null;
  private shelfStates: BiquadState[];
  private peakStates: BiquadState[];

  constructor(
    public readonly name: string,
    private calcFn: BiquadCoeffsFn,
    private activeFn: () => boolean,
    channels: number,
  ) {
    this.shelfStates = Array.from({ length: channels }, () => ({ x1: 0, x2: 0, y1: 0, y2: 0 }));
    this.peakStates = Array.from({ length: channels }, () => ({ x1: 0, x2: 0, y1: 0, y2: 0 }));
  }

  isActive(): boolean {
    return this.activeFn();
  }

  invalidate(): void {
    this.coeffs = null;
  }

  process(samples: Float64Array, channels: number, frames: number): void {
    if (samples.length === 0) return;
    if (!this.coeffs) this.coeffs = this.calcFn();

    const { shelf, peak } = this.coeffs;
    const limit = Math.min(channels, this.shelfStates.length);

    for (let ch = 0; ch < limit; ch++) {
      processBiquadChannel(samples, ch, channels, frames, shelf, peak, this.shelfStates[ch]!, this.peakStates[ch]!);
    }
  }

  reset(): void {
    this.coeffs = null;
    for (const st of this.shelfStates) { st.x1 = 0; st.x2 = 0; st.y1 = 0; st.y2 = 0; }
    for (const st of this.peakStates) { st.x1 = 0; st.x2 = 0; st.y1 = 0; st.y2 = 0; }
  }
}
